args.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
SELECT DISTINCT ?inst ?label ?yr ?itemMass ?u WHERE {
  ?inst a futuram:elvEmbeddedElectronics ;
        rdfs:label ?label .
  OPTIONAL { ?inst futuram:referenceYear ?yr }
  OPTIONAL { ?inst futuram:itemMass [ qudt:numericValue ?itemMass ; qudt:unit ?u ] }
} ORDER BY ?yr

