PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?pr ?node ?refLabel ?v ?u WHERE {
  <https://www.purl.org/futuram/example#V0301030000_2025> futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?node .
  ?node rdfs:label ?refLabel .
  OPTIONAL { ?pr futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit ?u ] }
} LIMIT 50

