PREFIX mw: <https://purl.org/metalwheel#>
SELECT DISTINCT ?s ?o WHERE {
  ?s ?p ?o .
  FILTER(?p = mw:hasExpectedRecoveryEffectiveness || ?p = mw:hasType)
} LIMIT 50

